// The page is server-rendered; when applications are closed it contains
// the Spanish text "Las aplicaciones estan cerradas" (Applications are
// closed). Absence of that marker means the page changed - most likely
// because applications opened.
const html = String($input.first().json.data ?? $input.first().json ?? '');
const isClosed = /cerradas/i.test(html);
const available = html.length > 0 && !isClosed;

// Persist state across executions (n8n workflow static data) so we only
// notify once on the closed -> open transition, not on every 3-hour check
// while it stays open. Closed checks never notify.
const staticData = $getWorkflowStaticData('global');
const wasAvailable = staticData.wasAvailable === true;
staticData.wasAvailable = available;
staticData.lastCheckedAt = new Date().toISOString();

if (!available || wasAvailable) {
  // Still closed, or already notified for this open window: stop here by
  // returning no items so the downstream Telegram node does not run.
  return [];
}

return [{
  json: {
    text: `🎉 Torrenteros applications are OPEN!\nhttps://torrenteros.org/application\nChecked at: ${staticData.lastCheckedAt}`,
  },
}];

// The HTTP request to Browserless failed after retries (e.g. network
// error, Cloudflare block, Browserless down). Always notify on error -
// unlike the closed/open check, this path is not deduplicated, since each
// failure is worth knowing about.
const item = $input.first().json;
const err = item.error ?? item;
const message = (err && err.message) ? err.message : JSON.stringify(err).slice(0, 300);

return [{
  json: {
    text: `⚠️ Failed to check Torrenteros application page: ${message}`,
  },
}];
